import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './Cart.css';

const Cart = ({ addToCart }) => {
  const [flowers, setFlowers] = useState([]);
  const [loading, setLoading] = useState(true);
  const defaultFlowers = [
    { id: 101, name: "Red Rose", price: 1500, url: "data:image/jpeg;base64,", description: "Classic deep red rose for romantic occasions." },
    { id: 102, name: "White Lily", price: 2200, url: "https://images.unsplash.com/photo-1508610048659-a06b669e3321?q=80&w=500", description: "Elegant white lilies with a soothing fragrance." },
    { id: 103, name: "Sun Flower", price: 1200, url: "https://images.unsplash.com/photo-1470509037663-253afd7f0f51?q=80&w=500", description: "Bright yellow sunflowers to light up your day." },
    { id: 104, name: "Tulips Mix", price: 3500, url: "data:image/jpeg;base64,", description: "Premium colorful tulips imported from Holland." },
    { id: 105, name: "Orchid Purple", price: 4500, url: "data:image/jpeg;base64,", description: "Exotic purple orchids for luxury gifting." },
    { id: 106, name: "Pink Peony", price: 2800, url: "data:image/jpeg;base64,", description: "Soft pink peonies, perfect for wedding bouquets." }
  ];

  useEffect(() => {
    fetchFlowers();
  }, []);

  const fetchFlowers = async () => {
    try {
      const response = await axios.get("http://localhost:8080/api/flowers/all");
      if (response.data.length > 0) {
        setFlowers(response.data);
      } else {
        setFlowers(defaultFlowers);
      }
      setLoading(false);
    } catch (error) {
      console.error("Error fetching flowers, showing defaults:", error);
      setFlowers(defaultFlowers);
      setLoading(false);
    }
  };

  const handleBuyClick = (e, flower) => {
    e.preventDefault(); 
    e.stopPropagation(); 
    addToCart(flower);
    alert(`Added ${flower.name} to your basket!`);
  };

  if (loading) return <div className="loader-container"><p>Loading Flowers...</p></div>;

  return (
    <div className="cart-wrapper">
      <h1 className="page-title">Our Flower Collection</h1>
      <div className="cart-grid">
        {flowers.map((flower) => (
          <div key={flower.id} className="cartstyle">
            <div className="carturl">
              <img src={flower.url} alt={flower.name} className="cartimage1" />
            </div>
            <div className="flower-details">
              <h3 className="nameofflower">{flower.name}</h3>
              <p className="priceofcart">Rs. {flower.price} /=</p>
              <p className="description-text">{flower.description}</p>
              <button 
                className="buy-button" 
                onClick={(e) => handleBuyClick(e, flower)}
              >
                Add to Cart
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Cart;